import cmath
import wavefunctions
def RFSC1_2(F2,S3,COUP,M1,W1):
    OM1 = 0.0
    if (M1): OM1=1.0/M1**2
    R1 = wavefunctions.WaveFunction(size=18)
    R1.momenta[0] = +F2.momenta[0]+S3.momenta[0]
    R1.momenta[1] = +F2.momenta[1]+S3.momenta[1]
    R1.momenta[2] = +F2.momenta[2]+S3.momenta[2]
    R1.momenta[3] = +F2.momenta[3]+S3.momenta[3]
    P1 = [-R1.momenta[j] for j in range(4)]
    flv_index1 = F1.flavor
    flv_index2 = F2.flavor
    if flv_index1 != -1 and flv_index2 != -1 and flv_index1 != flv_index2:
        return R1
    denom = COUP/(P1[0]**2-P1[1]**2-P1[2]**2-P1[3]**2 - M1 * (M1 -1j* W1))
    R1.W[0]= denom*1j/3 * M1*S3.W[0]*(OM1*(P1[0]*(F2.W[2]*(M1*M1*OM1*(-P1[0]+P1[3])+(+2*(P1[0])-P1[3]))+F2.W[3]*(M1*M1*OM1*(P1[1]-1j*(P1[2]))+(-P1[1]+1j*(P1[2]))))-F2.W[2]*(P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2]))-F2.W[2])
    R1.W[4]= denom*-1j/3 * M1*S3.W[0]*(OM1*(P1[1]*(F2.W[2]*(M1*M1*OM1*(P1[0]-P1[3])+(-P1[0]+P1[3]))+F2.W[3]*(M1*M1*OM1*(-P1[1]+1j*(P1[2]))+(+2*(P1[1])-1j*(P1[2]))))+F2.W[3]*(P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0]))+F2.W[3])
    R1.W[8]= denom*-1/3 * M1*S3.W[0]*(OM1*(P1[2]*(F2.W[2]*(M1*M1*OM1*(+1j*(P1[0])-1j*(P1[3]))+(-1j*(P1[0])+1j*(P1[3])))+F2.W[3]*(M1*-M1*OM1*(+1j*(P1[1])+P1[2])+(+1j*(P1[1])+2*(P1[2]))))+F2.W[3]*(P1[1]*P1[1]+P1[3]*P1[3]-P1[0]*P1[0]))+F2.W[3])
    R1.W[12]= denom*-1j/3 * M1*S3.W[0]*(OM1*(P1[3]*(F2.W[2]*(M1*M1*OM1*(P1[0]-P1[3])+(-P1[0]+2*(P1[3])))+F2.W[3]*(M1*M1*OM1*(-P1[1]+1j*(P1[2]))+(P1[1]-1j*(P1[2]))))+F2.W[2]*(-P1[0]*P1[0]+P1[1]*P1[1]+P1[2]*P1[2]))+F2.W[2])
    R1.W[1]= denom*1j/3 * M1*S3.W[0]*(OM1*(P1[0]*(F2.W[2]*(M1*M1*OM1*(P1[1]+1j*(P1[2]))+(-P1[1]-1j*(P1[2])))+F2.W[3]*(M1*-M1*OM1*(P1[0]+P1[3])+(+2*(P1[0])+P1[3])))-F2.W[3]*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]))-F2.W[3])
    R1.W[5]= denom*-1j/3 * M1*S3.W[0]*(OM1*(P1[1]*(F2.W[2]*(M1*-M1*OM1*(P1[1]+1j*(P1[2]))+(+2*(P1[1])+1j*(P1[2])))+F2.W[3]*(M1*M1*OM1*(P1[0]+P1[3])+(-P1[0]-P1[3])))+F2.W[2]*(-P1[0]*P1[0]+P1[3]*P1[3]+P1[2]*P1[2]))+F2.W[2])
    R1.W[9]= denom*1/3 * M1*S3.W[0]*(OM1*(P1[2]*(F2.W[2]*(M1*M1*OM1*(+1j*(P1[1])-P1[2])+(-1j*(P1[1])+2*(P1[2])))+F2.W[3]*(M1*-M1*OM1*(+1j*(P1[0]+P1[3]))+(+1j*(P1[0]+P1[3]))))+F2.W[2]*(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]))+F2.W[2])
    R1.W[13]= denom*1j/3 * M1*S3.W[0]*(OM1*(P1[3]*(F2.W[2]*(M1*M1*OM1*(P1[1]+1j*(P1[2]))+(-P1[1]-1j*(P1[2])))+F2.W[3]*(M1*-M1*OM1*(P1[0]+P1[3])+(P1[0]+2*(P1[3]))))+F2.W[3]*(P1[1]*P1[1]+P1[2]*P1[2]-P1[0]*P1[0]))+F2.W[3])
    R1.W[2]= denom*1j * S3.W[0]*(F2.W[2]*(OM1*(P1[0]*(M1*M1*(OM1*(-1/3)*(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2])+ -5/3)+(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2]))+1/3*(P1[3]*M1*M1))+(+7/3*(P1[0])-1/3*(P1[3])))+F2.W[3]*(M1*1/3 * M1*OM1*(P1[1]-1j*(P1[2]))+(-1/3*(P1[1])+1j/3*(P1[2]))))
    R1.W[6]= denom*1j * S3.W[0]*(F2.W[2]*(OM1*(P1[1]*(M1*M1*(OM1*(-1/3)*(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2])+ -5/3)+(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2]))-1j/3*(P1[2]*M1*M1))+(+7/3*(P1[1])+1j/3*(P1[2])))+F2.W[3]*(M1*1/3 * M1*OM1*(P1[0]+P1[3])+(-1/3*(P1[0]+P1[3]))))
    R1.W[10]= denom*1/3 * S3.W[0]*(F2.W[2]*(OM1*(P1[2]*(M1*M1*(OM1*(-1)*(-1j*(P1[0]*P1[0])+1j*(P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2]))+ -5j)+(-3j*(P1[0]*P1[0])+3j*(P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2])))-P1[1]*M1*M1)+(P1[1]+7j*(P1[2])))+F2.W[3]*(M1*M1*OM1*(P1[0]+P1[3])+(-P1[0]-P1[3])))
    R1.W[14]= denom*1j * S3.W[0]*(F2.W[2]*(OM1*(P1[3]*(M1*M1*(OM1*(-1/3)*(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2])+ -5/3)+(-P1[0]*P1[0]+P1[3]*P1[3]+P1[1]*P1[1]+P1[2]*P1[2]))+1/3*(P1[0]*M1*M1))+(-1/3*(P1[0])+7/3*(P1[3])))+F2.W[3]*(M1*1/3 * M1*OM1*(-P1[1]+1j*(P1[2]))+(+1/3*(P1[1])-1j/3*(P1[2]))))
    R1.W[3]= denom*1j * S3.W[0]*(F2.W[3]*(OM1*(P1[0]*(M1*M1*(OM1*(-1/3)*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0])+ -5/3)+(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0]))-1/3*(P1[3]*M1*M1))+(+7/3*(P1[0])+1/3*(P1[3])))+F2.W[2]*(M1*1/3 * M1*OM1*(P1[1]+1j*(P1[2]))+(-1/3*(P1[1])-1j/3*(P1[2]))))
    R1.W[7]= denom*1j * S3.W[0]*(F2.W[3]*(OM1*(P1[1]*(M1*M1*(OM1*(-1/3)*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0])+ -5/3)+(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0]))+1j/3*(P1[2]*M1*M1))+(+7/3*(P1[1])-1j/3*(P1[2])))+F2.W[2]*(M1*1/3 * M1*OM1*(P1[0]-P1[3])+(-1/3*(P1[0])+1/3*(P1[3]))))
    R1.W[11]= denom*-1/3 * S3.W[0]*(F2.W[3]*(OM1*(P1[2]*(M1*M1*(OM1*(+1j*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3])-1j*(P1[0]*P1[0]))+ 5j)+(-3j*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3])+3j*(P1[0]*P1[0])))-P1[1]*M1*M1)+(P1[1]-7j*(P1[2])))+F2.W[2]*(M1*M1*OM1*(P1[0]-P1[3])+(-P1[0]+P1[3])))
    R1.W[15]= denom*1j * S3.W[0]*(F2.W[3]*(OM1*(P1[3]*(M1*M1*(OM1*(-1/3)*(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0])+ -5/3)+(P1[1]*P1[1]+P1[2]*P1[2]+P1[3]*P1[3]-P1[0]*P1[0]))-1/3*(P1[0]*M1*M1))+(+1/3*(P1[0])+7/3*(P1[3])))+F2.W[2]*(M1*1/3 * M1*OM1*(P1[1]+1j*(P1[2]))+(-1/3*(P1[1])-1j/3*(P1[2]))))
    return R1


